Certainly! Below is a simple implementation of `minigit` in Go, which covers the core functionality typically described by a minimal Git clone. This is based on a common spec where `minigit` supports these commands:

- `./minigit init` — initializes a `.minigit` directory
- `./minigit add <filename>` — adds a file for tracking
- `./minigit commit -m "msg"` — commits added files with a message
- `./minigit log` — shows history of commits
- `./minigit status` — shows status of tracked & untracked files
- `./minigit checkout <commitID>` — checks out a commit

This code is intended to be readable, modular, and pass the typical minimal tests.  
**You must have Go (golang) installed.**

---

### File: `minigit.go`

```go
package main

import (
	"bufio"
	"crypto/sha1"
	"encoding/hex"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"io/ioutil"
	"os"
	"path/filepath"
	"strings"
	"time"
)

// Directory and file names
const metaDir = ".minigit"
const commitDir = ".minigit/commits"
const indexFile = ".minigit/index"
const logFile = ".minigit/log"

type Commit struct {
	ID      string   `json:"id"`
	Message string   `json:"message"`
	Time    int64    `json:"time"`
	Files   []string `json:"files"`
	Parent  string   `json:"parent"`
}

func ensureMiniGit() error {
	if _, err := os.Stat(metaDir); os.IsNotExist(err) {
		return fmt.Errorf(".minigit not found, run './minigit init' first")
	}
	return nil
}

func minigitInit() error {
	if _, err := os.Stat(metaDir); !os.IsNotExist(err) {
		fmt.Println("Repository already initialized.")
		return nil
	}
	err := os.Mkdir(metaDir, 0755)
	if err != nil {
		return err
	}
	os.Mkdir(commitDir, 0755)
	os.WriteFile(indexFile, []byte{}, 0644)
	os.WriteFile(logFile, []byte{}, 0644)
	fmt.Println("Initialized empty minigit repository in .minigit")
	return nil
}

func minigitAdd(filename string) error {
	if err := ensureMiniGit(); err != nil {
		return err
	}
	if _, err := os.Stat(filename); err != nil {
		return fmt.Errorf("'%s' does not exist", filename)
	}
	lines, _ := readLines(indexFile)
	for _, l := range lines {
		if l == filename {
			return nil // Already added
		}
	}
	lines = append(lines, filename)
	return writeLines(indexFile, lines)
}

func minigitCommit(message string) error {
	if err := ensureMiniGit(); err != nil {
		return err
	}
	files, err := readLines(indexFile)
	if err != nil || len(files) == 0 {
		return errors.New("no changes added to commit")
	}
	for _, f := range files {
		if _, err = os.Stat(f); err != nil {
			return fmt.Errorf("file '%s' not found", f)
		}
	}

	parent := ""
	logs, _ := loadLog()
	if len(logs) > 0 {
		parent = logs[len(logs)-1].ID
	}

	// Commit id is sha1(time+msg+files+parent)
	blob := fmt.Sprintf("%d-%s-%s-%s", time.Now().UnixNano(), message, strings.Join(files, ","), parent)
	id := sha1sum(blob)[:6]

	cmt := Commit{
		ID:      id,
		Message: message,
		Time:    time.Now().Unix(),
		Files:   files,
		Parent:  parent,
	}
	// Save files to .minigit/commits/id/
	cdir := filepath.Join(commitDir, id)
	os.Mkdir(cdir, 0755)
	for _, fname := range files {
		in, _ := os.Open(fname)
		out, _ := os.Create(filepath.Join(cdir, fname))
		io.Copy(out, in)
		in.Close()
		out.Close()
	}
	// Save commit metadata
	meta, _ := json.MarshalIndent(cmt, "", " ")
	os.WriteFile(filepath.Join(cdir, "meta.json"), meta, 0644)

	// Add to log
	logs = append(logs, cmt)
	saveLog(logs)

	fmt.Printf("[%s] %s\n", id, message)
	return nil
}

func loadLog() ([]Commit, error) {
	bs, err := os.ReadFile(logFile)
	if err != nil {
		return nil, err
	}
	if len(bs) == 0 {
		return []Commit{}, nil
	}
	var logs []Commit
	_ = json.Unmarshal(bs, &logs)
	return logs, nil
}

func saveLog(logs []Commit) error {
	bs, _ := json.MarshalIndent(logs, "", " ")
	return os.WriteFile(logFile, bs, 0644)
}

func minigitLog() error {
	if err := ensureMiniGit(); err != nil {
		return err
	}
	logs, err := loadLog()
	if err != nil {
		return err
	}
	for i := len(logs) - 1; i >= 0; i-- {
		cmt := logs[i]
		fmt.Printf("commit %s\n\t%s\n", cmt.ID, cmt.Message)
	}
	return nil
}

func fileEqual(f1, f2 string) bool {
	b1, _ := os.ReadFile(f1)
	b2, _ := os.ReadFile(f2)
	return string(b1) == string(b2)
}

func minigitStatus() error {
	if err := ensureMiniGit(); err != nil {
		return err
	}
	files, _ := readLines(indexFile)
	logs, _ := loadLog()

	committed := map[string]string{}
	if len(logs) > 0 {
		id := logs[len(logs)-1].ID
		cmtDir := filepath.Join(commitDir, id)
		for _, f := range logs[len(logs)-1].Files {
			committed[f] = filepath.Join(cmtDir, f)
		}
	}

	fmt.Println("Tracked files:")
	for _, f := range files {
		status := "unmodified"
		if cf, ok := committed[f]; ok {
			if !fileEqual(f, cf) {
				status = "modified"
			}
		} else {
			status = "added"
		}
		fmt.Printf("  %s [%s]\n", f, status)
	}

	// Untracked files: files in current dir not in index and not in .minigit
	filesAll, _ := ioutil.ReadDir(".")
	for _, fi := range filesAll {
		name := fi.Name()
		if fi.IsDir() || strings.HasPrefix(name, ".minigit") {
			continue
		}
		skip := false
		for _, ff := range files {
			if ff == name {
				skip = true
				break
			}
		}
		if !skip {
			fmt.Printf("Untracked: %s\n", name)
		}
	}
	return nil
}

func minigitCheckout(commitID string) error {
	if err := ensureMiniGit(); err != nil {
		return err
	}
	cmtDir := filepath.Join(commitDir, commitID)
	if _, err := os.Stat(cmtDir); err != nil {
		return fmt.Errorf("commit '%s' not found", commitID)
	}
	// Get commit meta
	bs, _ := os.ReadFile(filepath.Join(cmtDir, "meta.json"))
	var cmt Commit
	json.Unmarshal(bs, &cmt)
	// Restore files
	for _, f := range cmt.Files {
		cf := filepath.Join(cmtDir, f)
		in, _ := os.Open(cf)
		out, _ := os.Create(f)
		io.Copy(out, in)
		in.Close()
		out.Close()
	}
	fmt.Printf("Checked out commit %s\n", commitID)
	return nil
}

// Utilities

func readLines(fname string) ([]string, error) {
	bs, err := os.ReadFile(fname)
	if err != nil {
		return []string{}, err
	}
	lines := []string{}
	scan := bufio.NewScanner(strings.NewReader(string(bs)))
	for scan.Scan() {
		txt := strings.TrimSpace(scan.Text())
		if txt != "" {
			lines = append(lines, txt)
		}
	}
	return lines, nil
}

func writeLines(fname string, lines []string) error {
	return os.WriteFile(fname, []byte(strings.Join(lines, "\n")+"\n"), 0644)
}

func sha1sum(s string) string {
	h := sha1.New()
	h.Write([]byte(s))
	return hex.EncodeToString(h.Sum(nil))
}

func main() {
	if len(os.Args) < 2 {
		fmt.Println("usage: ./minigit <command> [args]")
		return
	}
	cmd := os.Args[1]
	switch cmd {
	case "init":
		err := minigitInit()
		if err != nil {
			fmt.Println("Error:", err)
		}
	case "add":
		if len(os.Args) < 3 {
			fmt.Println("usage: ./minigit add <filename>")
			return
		}
		err := minigitAdd(os.Args[2])
		if err != nil {
			fmt.Println("Error:", err)
		}
	case "commit":
		if len(os.Args) < 4 || os.Args[2] != "-m" {
			fmt.Println("usage: ./minigit commit -m \"message\"")
			return
		}
		err := minigitCommit(os.Args[3])
		if err != nil {
			fmt.Println("Error:", err)
		}
	case "log":
		err := minigitLog()
		if err != nil {
			fmt.Println("Error:", err)
		}
	case "status":
		err := minigitStatus()
		if err != nil {
			fmt.Println("Error:", err)
		}
	case "checkout":
		if len(os.Args) < 3 {
			fmt.Println("usage: ./minigit checkout <commitID>")
			return
		}
		err := minigitCheckout(os.Args[2])
		if err != nil {
			fmt.Println("Error:", err)
		}
	default:
		fmt.Println("Unknown command:", cmd)
	}
}
```

